/**
 * WordPress Dependencies
 */
import { __ } from "@wordpress/i18n";
import { assign, isEmpty } from "lodash";
import { select } from "@wordpress/data";
import { addFilter } from "@wordpress/hooks";
import { useEffect } from "@wordpress/element";
import { createHigherOrderComponent } from "@wordpress/compose";
/**
 * Custom Imports
 */
// import "./variations";
import "./style.scss";
import "./editor.scss";
import variations from "./variations";
import { getBorder } from "./utils";
import CustomInspectorControls from "./inspector-controls";
import "./extensions";
/**
 * Add new attributes to the block
 */
const addAttributes = (props) => {
	const { attributes } = props;

	if (isEmpty(attributes) || props.name !== "core/query") {
		return props;
	}

	props.variations = [...props.variations, ...variations];

	props.attributes = assign(
		props.attributes,
		{
			...attributes,
			gutenberghubVariation: {
				type: "string",
				default: "default",
			},
			gutenberghubAutoPlayDelay: {
				type: "number",
				default: 3000,
			},
			ghubSpeed: {
				type: "number",
				default: 400,
			},

			gutenberghubPauseOnHover: {
				type: "boolean",
				default: false,
			},

			gutenberghubAutoPlayOn: {
				type: "boolean",
				default: false,
			},

			ghubLoopOn: {
				type: "boolean",
				default: false,
			},

			gutenberghubHeight: {
				type: "string",
				default: "equal",
			},
			gutenberghubNavigationOn: {
				type: "boolean",
				default: true,
			},

			gutenberghubNavigationIcon: {
				type: "string",
				default: "arrow",
			},

			gutenberghubNavigationVerticalAlign: {
				type: "string",
				default: "center",
			},

			gutenberghubNavigationJustification: {
				type: "string",
				default: "spaceBetween",
			},

			gutenberghubNavigationSize: {
				type: "string",
				default: "32px",
			},

			gutenberghubIndicatorOn: {
				type: "boolean",
				default: false,
			},

			gutenberghubIndicatorStyle: {
				type: "string",
				default: "slider-indicators-round",
			},

			gutenberghubIndicatorVerticalAlign: {
				type: "string",
				default: "bottom",
			},

			gutenberghubIndicatorJustification: {
				type: "string",
				default: "center",
			},
			gutenberghubIndicatorSize: {
				type: "string",
				default: "18px",
			},

			gutenberghubSlidesGap: {
				type: "number",
				default: 20,
			},
			navigationColor: {
				type: "string",
				default: "",
			},
			paginationColor: {
				type: "string",
				default: "#0693E3",
			},
			inActivePaginationColor: {
				type: "string",
				default: "#cccccc",
			},
			ghubSlideBgColor: {
				type: "string",
				default: "",
			},
			ghubSlidePadding: {
				type: "object",
				default: {},
			},
			ghubSlideRadius: {
				type: "object",
				default: {},
			},
			ghubSlideBorder: {
				type: "object",
				default: {},
			},
			sliderDirection: {
				type: "string",
				default: "horizontal",
			},
			navigationBgColor: {
				type: "string",
				default: "",
			},
			navigationBorder: {
				type: "object",
				default: {},
			},
			navigationBorderRadius: {
				type: "object",
				default: {},
			},
		},
		{}
	);

	return props;
};

const withAdvanceControls = createHigherOrderComponent((BlockEdit) => {
	return (props) => {
		const { name } = props;
		const { gutenberghubVariation } = props.attributes;

		if (
			name !== "core/query" ||
			(name === "core/query" && "ghub-query-slider" !== gutenberghubVariation)
		) {
			return <BlockEdit {...props} />;
		}
		const block = select("core/block-editor").getBlock(props.clientId);
		if (block.innerBlocks.length <= 0) {
			return <BlockEdit {...props} />;
		}

		return (
			<>
				<BlockEdit {...props} />
				<CustomInspectorControls {...props} />
			</>
		);
	};
}, "withAdvanceControls");

const withBlockWrapper = createHigherOrderComponent((BlockListBlock) => {
	return (props) => {
		const {
			ghubSlideBgColor,
			ghubSlideBorder,
			ghubSlidePadding,
			ghubSlideRadius,
			gutenberghubNavigationIcon,
			gutenberghubNavigationSize,
			navigationColor,
			gutenberghubNavigationVerticalAlign,
			gutenberghubNavigationJustification,
			gutenberghubNavigationOn,
			gutenberghubIndicatorOn,
			gutenberghubIndicatorSize,
			inActivePaginationColor,
			paginationColor,
			gutenberghubIndicatorVerticalAlign,
			gutenberghubIndicatorJustification,
			gutenberghubIndicatorStyle,
			gutenberghubSlidesGap,
			gutenberghubHeight,
			gutenberghubVariation,
			navigationBgColor,
			navigationBorder,
			navigationBorderRadius,
		} = props.attributes;

		if (
			props.name !== "core/query" ||
			(props.name === "core/query" &&
				"ghub-query-slider" !== gutenberghubVariation)
		) {
			return <BlockListBlock {...props} />;
		}
		const block = select("core/block-editor").getBlock(props.clientId);
		if (block.innerBlocks.length <= 0) {
			return <BlockListBlock {...props} />;
		}

		function get_navigation_icon(icon_name) {
			const icons = {
				chevron: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32">
						<path
							fill="currentColor"
							d="M22 16L12 26l-1.4-1.4l8.6-8.6l-8.6-8.6L12 6z"
						/>
					</svg>
				),

				chevronCompact: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16">
						<path
							fill="currentColor"
							fill-rule="evenodd"
							d="M6.776 1.553a.5.5 0 0 1 .671.223l3 6a.5.5 0 0 1 0 .448l-3 6a.5.5 0 1 1-.894-.448L9.44 8L6.553 2.224a.5.5 0 0 1 .223-.671z"
						/>
					</svg>
				),

				squareChevron: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
						<path
							fill="currentColor"
							d="M19 3H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14c1.11 0 2-.89 2-2V5a2 2 0 0 0-2-2M9.71 18l-1.42-1.41L12.88 12L8.29 7.41L9.71 6l6 6l-6 6Z"
						/>
					</svg>
				),

				caretFill: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16">
						<path
							fill="currentColor"
							d="m12.14 8.753l-5.482 4.796c-.646.566-1.658.106-1.658-.753V3.204a1 1 0 0 1 1.659-.753l5.48 4.796a1 1 0 0 1 0 1.506z"
						/>
					</svg>
				),

				roundArrow: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 256 256">
						<path
							fill="currentColor"
							d="M128 24a104 104 0 1 0 104 104A104.2 104.2 0 0 0 128 24Zm47.4 107.1a8.7 8.7 0 0 1-1.8 2.6l-33.9 33.9a7.6 7.6 0 0 1-5.6 2.3a7.8 7.8 0 0 1-5.7-2.3a8 8 0 0 1 0-11.3l20.3-20.3H88a8 8 0 0 1 0-16h60.7l-20.3-20.3a8 8 0 0 1 11.3-11.3l33.9 33.9a8.7 8.7 0 0 1 1.8 2.6a8.3 8.3 0 0 1 0 6.2Z"
						/>
					</svg>
				),

				arrow: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
						<path
							fill="currentColor"
							d="m12 4l-1.41 1.41L16.17 11H4v2h12.17l-5.58 5.59L12 20l8-8l-8-8z"
						/>
					</svg>
				),

				caret: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 16 16">
						<path
							fill="currentColor"
							d="M6 12.796V3.204L11.481 8L6 12.796zm.659.753l5.48-4.796a1 1 0 0 0 0-1.506L6.66 2.451C6.011 1.885 5 2.345 5 3.204v9.592a1 1 0 0 0 1.659.753z"
						/>
					</svg>
				),

				roundIndicators: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
						<path
							fill="currentColor"
							d="M16 12a2 2 0 0 1 2-2a2 2 0 0 1 2 2a2 2 0 0 1-2 2a2 2 0 0 1-2-2m-6 0a2 2 0 0 1 2-2a2 2 0 0 1 2 2a2 2 0 0 1-2 2a2 2 0 0 1-2-2m-6 0a2 2 0 0 1 2-2a2 2 0 0 1 2 2a2 2 0 0 1-2 2a2 2 0 0 1-2-2Z"
						/>
					</svg>
				),

				squareIndicators: (
					<svg
						width="12"
						height="2"
						viewBox="0 0 12 2"
						fill="none"
						xmlns="http://www.w3.org/2000/svg"
					>
						<rect width="2" height="2" fill="currentColor" />
						<rect x="5" width="2" height="2" fill="currentColor" />
						<rect x="10" width="2" height="2" fill="currentColor" />
					</svg>
				),

				dashIndicators: (
					<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
						<path
							fill="currentColor"
							d="M4 11h4v2H4v-2Zm6 0h4v2h-4v-2Zm10 0h-4v2h4v-2Z"
						/>
					</svg>
				),
			};
			return icons[icon_name];
		}

		const ghubVariables = {
			"--ghub-slide-bg-color": ghubSlideBgColor,
			"--ghub-slide-padding-top": ghubSlidePadding?.top,
			"--ghub-slide-padding-left": ghubSlidePadding?.left,
			"--ghub-slide-padding-bottom": ghubSlidePadding?.bottom,
			"--ghub-slide-padding-right": ghubSlidePadding?.right,
			"--ghub-slide-radius-top-left": ghubSlideRadius?.top,
			"--ghub-slide-radius-top-right": ghubSlideRadius?.right,
			"--ghub-slide-radius-bottom-left": ghubSlideRadius?.bottom,
			"--ghub-slide-radius-bottom-right": ghubSlideRadius?.left,
			"--ghub-slide-outline-top-width": ghubSlideBorder?.top?.width,
			"--ghub-slide-outline-top-style":
				ghubSlideBorder?.top?.width && isEmpty(ghubSlideBorder?.top?.style)
					? "solid"
					: ghubSlideBorder?.top?.style ?? "",
			"--ghub-slide-outline-top-color": ghubSlideBorder?.top?.color,
			"--ghub-slide-outline-right-width": ghubSlideBorder?.right?.width,
			"--ghub-slide-outline-right-style":
				ghubSlideBorder?.right?.width && isEmpty(ghubSlideBorder?.right?.style)
					? "solid"
					: ghubSlideBorder?.right?.style ?? "",
			"--ghub-slide-outline-right-color": ghubSlideBorder?.right?.color,
			"--ghub-slide-outline-bottom-width": ghubSlideBorder?.bottom?.width,
			"--ghub-slide-outline-bottom-style":
				ghubSlideBorder?.bottom?.width &&
				isEmpty(ghubSlideBorder?.bottom?.style)
					? "solid"
					: ghubSlideBorder?.bottom?.style ?? "",
			"--ghub-slide-outline-bottom-color": ghubSlideBorder?.bottom?.color,
			"--ghub-slide-outline-left-width": ghubSlideBorder?.left?.width,
			"--ghub-slide-outline-left-style":
				ghubSlideBorder?.left?.width && isEmpty(ghubSlideBorder?.left?.style)
					? "solid"
					: ghubSlideBorder?.left?.style ?? "",
			"--ghub-slide-outline-left-color": ghubSlideBorder?.left?.color,
			"--ghub-slide-outline-width": ghubSlideBorder?.width,
			"--ghub-slide-outline-style":
				ghubSlideBorder?.width && isEmpty(ghubSlideBorder?.style)
					? "solid"
					: ghubSlideBorder?.style ?? "",
			"--ghub-slide-outline-color": ghubSlideBorder?.color,
			"--ghub-slider-gap": gutenberghubSlidesGap + "px",
		};
		const border = getBorder(navigationBorder);

		const navigationVariable = {
			"--ghub-slider-navigation-size": gutenberghubNavigationSize,
			"--ghub-slider-navigation-color": navigationColor,
			"--ghub-slider-navigation-bg-color": navigationBgColor,
			"--ghub-slider-navigation-radius-top-left": navigationBorderRadius?.top,
			"--ghub-slider-navigation-radius-top-right":
				navigationBorderRadius?.right,
			"--ghub-slider-navigation-radius-bottom-left":
				navigationBorderRadius?.bottom,
			"--ghub-slider-navigation-radius-bottom-right":
				navigationBorderRadius?.left,
			"--ghub-slider-navigation-border-top": `${border?.top?.width ?? ""} ${
				border?.top?.width && isEmpty(border?.top?.style)
					? "solid"
					: border?.top?.style ?? ""
			} ${border?.top?.color ?? ""}`,
			"--ghub-slider-navigation-border-right": `${border?.right?.width ?? ""} ${
				border?.right?.width && isEmpty(border?.right?.style)
					? "solid"
					: border?.right?.style ?? ""
			} ${border?.right?.color ?? ""}`,
			"--ghub-slider-navigation-border-bottom": `${
				border?.bottom?.width ?? ""
			} ${
				border?.bottom?.width && isEmpty(border?.bottom?.style)
					? "solid"
					: border?.bottom?.style ?? ""
			} ${border?.bottom?.color ?? ""}`,
			"--ghub-slider-navigation-border-left": `${border?.left?.width ?? ""} ${
				border?.left?.width && isEmpty(border?.left?.style)
					? "solid"
					: border?.left?.style ?? ""
			} ${border?.left?.color ?? ""}`,
		};

		const paginationVariable = {
			"--ghub-slider-pagination-size": gutenberghubIndicatorSize,
			"--ghub-slider-pagination-inactive-color": inActivePaginationColor,
			"--ghub-slider-pagination-active-color": paginationColor,
		};

		const navigationVerticalAlign =
			typeof gutenberghubNavigationVerticalAlign !== "undefined"
				? `ghub-navigation-vertical-${gutenberghubNavigationVerticalAlign}`
				: "ghub-navigation-vertical-center";

		const navigationJustification =
			typeof gutenberghubNavigationJustification !== "undefined"
				? `ghub-navigation-justify-${gutenberghubNavigationJustification}`
				: "ghub-navigation-justify-center";

		const paginationVerticalAlign =
			typeof gutenberghubIndicatorVerticalAlign !== "undefined"
				? `ghub-pagination-vertical-${gutenberghubIndicatorVerticalAlign}`
				: "ghub-pagination-vertical-bottom";

		const paginationJustification =
			typeof gutenberghubIndicatorJustification !== "undefined"
				? `ghub-pagination-justify-${gutenberghubIndicatorJustification}`
				: "ghub-pagination-justify-center";

		props.wrapperProps = {
			...props.wrapperProps,
			style: ghubVariables,
			className: "ghub-slider-wrapper-editor",
		};

		return (
			<div
				className={`ghub-slider-container-editor ghub-${gutenberghubHeight} ${
					!isEmpty(props.attributes.align)
						? "align" + props.attributes.align
						: ""
				}`}
			>
				<BlockListBlock {...props} {...props.wrapperProps} />
				{gutenberghubNavigationOn && (
					<div
						className={`ghub-navigation-wrapper ${navigationJustification} ${navigationVerticalAlign}`}
						style={navigationVariable}
					>
						<div className="ghub-slider-prev">
							{get_navigation_icon(gutenberghubNavigationIcon)}
						</div>
						<div className="ghub-slider-next">
							{get_navigation_icon(gutenberghubNavigationIcon)}
						</div>
					</div>
				)}

				{gutenberghubIndicatorOn && (
					<div
						className={`ghub-pagination-wrapper ${gutenberghubIndicatorStyle} ${paginationJustification} ${paginationVerticalAlign}`}
						style={paginationVariable}
					>
						<span className="ghub-pagination-bullet ghub-active"></span>
						<span className="ghub-pagination-bullet"></span>
						<span className="ghub-pagination-bullet"></span>
					</div>
				)}
			</div>
		);
	};
}, "withBlockWrapper");

addFilter(
	"editor.BlockEdit",
	"gutenberghub-query-slider-ext/with-advance-controls",
	withAdvanceControls
);
addFilter(
	"blocks.registerBlockType",
	"gutenberghub-query-slider-ext/add-attributes",
	addAttributes
);
addFilter(
	"editor.BlockListBlock",
	"gutenberghub-query-slider-ext/with-block-wrapper",
	withBlockWrapper
);
