/**
 * WordPress Dependencies
 */
import { isEqual } from "lodash";
import { __ } from "@wordpress/i18n";
import Icon from "./Icons";
import { loop } from "@wordpress/icons";

/** @typedef {import('@wordpress/blocks').WPBlockVariation} WPBlockVariation */

/**
 * Template option choices for predefined columns layouts.
 *
 * @type {WPBlockVariation[]}
 */

wp.blocks.registerBlockVariation("core/query", {
	title: __("Query Loop", "gutenberghub-slider-ext"),
	description: __(
		"Display multiple images in a rich gallery.",
		"gutenberghub-slider-ext"
	),
	icon: loop,
	name: "core/query",
	isDefault: true,
	attributes: {
		gutenberghubVariation: "default",
		className: "",
	},
	scope: ["inserter", "transform"],
	isActive: (blockAttributes, variationAttributes) =>
		isEqual(
			blockAttributes.gutenberghubVariation,
			variationAttributes.gutenberghubVariation
		),
});
wp.blocks.registerBlockVariation("core/query", {
	name: "gutenberghub-slider-query",
	title: __("Query Slider", "gutenberghub-query-slider-ext"),
	description: __(
		"The Query Slider Block enhances the default WordPress Post block by transforming it into a slider format, offering a more engaging way to display images in your posts or pages.",
		"gutenberghub-query-slider-ext"
	),
	keywords: ["gutenberg", "slider", "carousel", "query"],
	category: "ghub-products",
	icon: <Icon icon="querySlider" />,
	attributes: {
		gutenberghubVariation: "ghub-query-slider",
		className: "ghub-query-slider",
	},
	scope: ["transform", "inserter"],
	isActive: (blockAttributes, variationAttributes) =>
		isEqual(
			blockAttributes.gutenberghubVariation,
			variationAttributes.gutenberghubVariation
		),
});

const QUERY_ATTRIBUTES = {
	pages: 0,
	offset: 0,
	postType: "post",
	order: "desc",
	orderBy: "date",
	author: "",
	search: "",
	exclude: [],
	sticky: "",
	inherit: false,
};

const variations = [
	{
		name: "ghub-slider",
		title: __("Slider", "gutenberghub-query-slider-ext"),
		icon: <Icon icon="querySlider" />,
		attributes: {
			query: {
				...QUERY_ATTRIBUTES,
				perPage: 1,
			},
			gutenberghubVariation: "ghub-query-slider",
			gutenberghubHeight: "auto",
			gutenberghubAutoPlayOn: true,
			gutenberghubAutoPlayDelay: 2000,
			gutenberghubIndicatorOn: false,
			navigationColor: "#ffffff",
			gutenberghubNavigationIcon: "arrow",
			gutenberghubNavigationJustification: "spaceBetween",
			gutenberghubNavigationOn: true,
			gutenberghubNavigationSize: "36px",
			gutenberghubNavigationVerticalAlign: "center",
			navigationBgColor: "#000000",
			navigationBorderRadius: {
				top: "6px",
				right: "6px",
				bottom: "6px",
				left: "6px",
			},
		},
		innerBlocks: [
			[
				"core/post-template",
				{},
				[["core/post-title"], ["core/post-date"], ["core/post-excerpt"]],
			],
			["core/query-no-results"],
		],
		scope: ["block"],
	},
];

export default variations;
