/**
 * WordPress Dependencies
 */
import { __ } from "@wordpress/i18n";
import {
	PanelBody,
	ToggleControl,
	RangeControl,
	ColorPalette,
	BaseControl,
	__experimentalBoxControl as BoxControl,
	__experimentalBorderBoxControl as BorderBoxControl,
	Button,
	ButtonGroup,
	Flex,
	Tip,
} from "@wordpress/components";
import { InspectorControls } from "@wordpress/block-editor";
import { AutoPlay, IndicatorsControl, NavigationControls } from "./components";
import { useSelect } from "@wordpress/data";

function CustomInspectorControls(props) {
	const { attributes, setAttributes } = props;

	const { defaultColors } = useSelect((select) => {
		return {
			defaultColors:
				select("core/block-editor")?.getSettings()?.__experimentalFeatures
					?.color?.palette?.default,
		};
	});

	return (
		<InspectorControls>
			<PanelBody
				initialOpen={false}
				title={__("Slider", "gutenberghub-query-slider-ext")}
			>
				<RangeControl
					min={1}
					max={6}
					allowReset
					resetFallbackValue={3}
					initialPosition={3}
					label={__("Slides Per View", "gutenberghub-query-slider-ext")}
					value={Number(attributes.query.perPage)}
					onChange={(newValue) =>
						setAttributes({
							query: { ...attributes.query, perPage: newValue.toString() },
						})
					}
				/>

				<RangeControl
					min={0}
					max={200}
					allowReset
					initialPosition={20}
					label={__("Slides Gap (px)", "gutenberghub-query-slider-ext")}
					value={attributes.gutenberghubSlidesGap}
					onChange={(newValue) =>
						setAttributes({ gutenberghubSlidesGap: newValue })
					}
				/>

				<RangeControl
					label={__("Speed (ms)", "gutenberghub-query-slider-ext")}
					initialPosition={400}
					allowReset
					min={100}
					max={2000}
					step={100}
					value={attributes.ghubSpeed}
					onChange={(newValue) => setAttributes({ ghubSpeed: newValue })}
				/>

				<Flex>
					<span>{__("HEIGHT", "gutenberghub-query-slider-ext")}</span>
					<ButtonGroup>
						<Button
							isPressed={
								attributes.gutenberghubHeight === "equal" ? true : false
							}
							onClick={() => setAttributes({ gutenberghubHeight: "equal" })}
						>
							{__("Equal", "gutenberghub-query-slider-ext")}
						</Button>
						<Button
							isPressed={
								attributes.gutenberghubHeight === "auto" ? true : false
							}
							onClick={() => setAttributes({ gutenberghubHeight: "auto" })}
						>
							{__("Auto", "gutenberghub-query-slider-ext")}
						</Button>
					</ButtonGroup>
				</Flex>
				<br />

				<ToggleControl
					label={__("Loop", "gutenberghub-query-slider-ext")}
					checked={attributes?.ghubLoopOn}
					onChange={() =>
						setAttributes({
							ghubLoopOn: !attributes?.ghubLoopOn,
						})
					}
				/>
				{attributes.ghubLoopOn && (
					<>
						<Tip>
							{__(
								"Not Recommended: Due to the nature of this feature, it might not work well with the Query Loop.",
								"gutenberghub-query-slider-ext"
							)}
						</Tip>
						<br />
					</>
				)}

				<ToggleControl
					label={__("Auto Play", "gutenberghub-query-slider-ext")}
					checked={attributes?.gutenberghubAutoPlayOn}
					onChange={() =>
						setAttributes({
							gutenberghubAutoPlayOn: !attributes?.gutenberghubAutoPlayOn,
						})
					}
				/>
				{attributes?.gutenberghubAutoPlayOn && <AutoPlay {...props} />}
				<ToggleControl
					label={__("Arrows", "gutenberghub-query-slider-ext")}
					checked={attributes?.gutenberghubNavigationOn}
					onChange={() =>
						setAttributes({
							gutenberghubNavigationOn: !attributes?.gutenberghubNavigationOn,
						})
					}
				/>

				<ToggleControl
					label={__("Indicators", "gutenberghub-query-slider-ext")}
					checked={attributes?.gutenberghubIndicatorOn}
					onChange={() =>
						setAttributes({
							gutenberghubIndicatorOn: !attributes?.gutenberghubIndicatorOn,
						})
					}
				/>
			</PanelBody>

			<PanelBody
				title={__("Slider Styling", "gutenberghub-query-slider-ext")}
				initialOpen={false}
			>
				<BaseControl
					label={__("Background Color", "gutenberghub-query-slider-ext")}
				>
					<ColorPalette
						colors={defaultColors}
						value={attributes.ghubSlideBgColor}
						onChange={(newValue) => {
							setAttributes({ ghubSlideBgColor: newValue });
						}}
					/>
				</BaseControl>

				<BoxControl
					label={__("Padding", "gutenberghub-query-slider-ext")}
					values={attributes.ghubSlidePadding}
					onChange={(newValue) => setAttributes({ ghubSlidePadding: newValue })}
				/>

				<BoxControl
					label={__("Border Radius", "gutenberghub-query-slider-ext")}
					values={attributes.ghubSlideRadius}
					onChange={(newValue) => setAttributes({ ghubSlideRadius: newValue })}
				/>

				<BorderBoxControl
					className="ghub-border-control-wrapper"
					colors={defaultColors}
					label={__("Border", "gutenberghub-query-slider-ext")}
					onChange={(newValue) => setAttributes({ ghubSlideBorder: newValue })}
					value={attributes.ghubSlideBorder}
				/>
			</PanelBody>

			{true === attributes.gutenberghubNavigationOn && (
				<PanelBody
					title={__("Navigation", "gutenberghub-query-slider-ext")}
					initialOpen={false}
				>
					<NavigationControls {...props} />
				</PanelBody>
			)}

			{true === attributes.gutenberghubIndicatorOn && (
				<PanelBody
					initialOpen={false}
					title={__("Indicator", "gutenberghub-query-slider-ext")}
				>
					<IndicatorsControl {...props} />
				</PanelBody>
			)}
		</InspectorControls>
	);
}

export default CustomInspectorControls;
