/**
 * WordPress Dependencies
 */
import { __ } from "@wordpress/i18n";
import {
	ToggleControl,
	RangeControl,
	BaseControl,
} from "@wordpress/components";

function AutoPlay(props) {
	const { attributes, setAttributes } = props;

	return (
		<BaseControl className="gutenberghub-slider-base-wrapper">
			<RangeControl
				min={0}
				max={10000}
				allowReset
				initialPosition={3000}
				value={attributes.gutenberghubAutoPlayDelay}
				label={__("Delay (ms)", "gutenberghub-query-slider-ext")}
				onChange={(newValue) => {
					setAttributes({ gutenberghubAutoPlayDelay: newValue });
				}}
			/>
		</BaseControl>
	);
}

export default AutoPlay;
